from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of building‑related triples into a fluent, natural‑language sentence.
    This version groups information by subject and builds a single, natural‑sounding
    sentence, handling common patterns such as “designed by … and located at …”.
    """
    if not triples:
        return ""

    # Helper to strip surrounding quotes from literals
    def clean(val: str) -> str:
        return val.strip().strip('"').strip("'")

    # Helper sets
    _definite_countries = {
        "United States", "United Kingdom", "Netherlands", "Philippines",
        "Czech Republic", "Dominican Republic", "United Arab Emirates",
        "Republic of the Congo", "Democratic Republic of the Congo",
        "Bahamas", "Gambia", "United States of America"
    }

    def _article(name: str) -> str:
        return f"the {name}" if name in _definite_countries else name

    # Collect triples per predicate for the first subject (assume all share same subject)
    subject = clean(triples[0].subject)
    info = {}
    for t in triples:
        pred = t.predicate
        obj = clean(t.object)
        # Apply article to country‑type objects
        if pred in {"location", "country", "isPartOf", "capital"}:
            obj = _article(obj)
        info[pred] = obj

    # Build the core sentence using common patterns
    parts = []

    # 1. Basic identification (building type or name)
    if "buildingType" in info:
        parts.append(f"{subject} is a {info['buildingType']}")
    else:
        parts.append(subject)

    # 2. Architect/designer
    if "architect" in info:
        parts.append(f"designed by {info['architect']}")
    elif "origin" in info:  # for persons
        parts.append(f"originates from {info['origin']}")

    # 3. Location
    if "location" in info:
        parts.append(f"located at {info['location']}")
    elif "address" in info:
        parts.append(f"addressed at {info['address']}")

    # 4. Additional attributes (height, floorCount, cost, etc.)
    extra_attrs = []
    for attr in ["height", "floorCount", "floorArea", "cost", "completionDate",
                 "buildingStartDate", "yearOfConstruction"]:
        if attr in info:
            label = {
                "height": "height of",
                "floorCount": "has",
                "floorArea": "covers a floor area of",
                "cost": "costs",
                "completionDate": "was completed in",
                "buildingStartDate": "started construction in",
                "yearOfConstruction": "was constructed in"
            }[attr]
            if attr == "floorCount":
                extra_attrs.append(f"{label} {info[attr]} floors")
            else:
                extra_attrs.append(f"{label} {info[attr]}")

    if extra_attrs:
        parts.append(", ".join(extra_attrs))

    # 5. Ownership / tenancy
    if "owner" in info:
        parts.append(f"owned by {info['owner']}")
    if "tenant" in info:
        parts.append(f"with tenant {info['tenant']}")
    if "currentTenants" in info:
        parts.append(f"currently houses {info['currentTenants']}")

    # 6. Country / region relationships
    if "country" in info:
        parts.append(f"in {info['country']}")
    if "isPartOf" in info:
        parts.append(f"part of {info['isPartOf']}")

    # Assemble sentence
    sentence = " ".join(parts).strip()
    if not sentence.endswith("."):
        sentence += "."

    # Capitalize first character
    return sentence[0].upper() + sentence[1:]

